#include <iostream>

int main() {
    std::cout << "=== Pointer Arithmetic ===" << std::endl;

    // Array of integers
    int numbers[5] = {10, 20, 30, 40, 50};
    int* ptr = numbers;  // Points to first element

    std::cout << "Array: ";
    for (int i = 0; i < 5; i++) {
        std::cout << numbers[i] << " ";
    }
    std::cout << std::endl;

    std::cout << "\n=== Traversing with pointer arithmetic ===" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << "*(ptr + " << i << ") = " << *(ptr + i) << std::endl;
    }

    std::cout << "\n=== Incrementing pointer ===" << std::endl;
    ptr = numbers;  // Reset
    std::cout << "*ptr: " << *ptr << std::endl;
    ptr++;  // Move to next element
    std::cout << "*ptr after ptr++: " << *ptr << std::endl;
    ptr++;
    std::cout << "*ptr after ptr++: " << *ptr << std::endl;

    std::cout << "\n=== Pointer difference ===" << std::endl;
    int* begin = numbers;
    int* end = numbers + 5;
    std::cout << "Number of elements: " << (end - begin) << std::endl;

    std::cout << "\n=== Pointer arithmetic with char ===" << std::endl;
    char letters[] = {'A', 'B', 'C', 'D', 'E'};
    char* charPtr = letters;
    std::cout << "char* size: " << sizeof(char*) << " bytes" << std::endl;
    std::cout << "charPtr: " << (void*)charPtr << std::endl;
    charPtr++;
    std::cout << "charPtr after ++: " << (void*)charPtr << std::endl;

    std::cout << "\n=== Pointer arithmetic with int ===" << std::endl;
    int* intPtr = numbers;
    std::cout << "int* size: " << sizeof(int*) << " bytes" << std::endl;
    std::cout << "intPtr: " << intPtr << std::endl;
    intPtr++;
    std::cout << "intPtr after ++: " << intPtr << std::endl;

    return 0;
}

