#include <iostream>

int main() {
    int scores[5] = {100, 90, 85, 95, 80};
    int* ptr = scores;

    std::cout << "=== Using pointer arithmetic ===" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << "*(ptr + " << i << ") = " << *(ptr + i) << std::endl;
    }

    std::cout << "\n=== Using ptr++ ===" << std::endl;
    ptr = scores;  // Reset
    for (int i = 0; i < 5; i++) {
        std::cout << "*ptr = " << *ptr << std::endl;
        ptr++;
    }

    std::cout << "\n=== Pointer difference ===" << std::endl;
    int* begin = scores;
    int* end = scores + 5;
    std::cout << "Number of elements: " << (end - begin) << std::endl;

    return 0;
}
